{"procName":"dbo.sp_fixluyke_toanbo","body":"CREATE   PROCEDURE dbo.sp_FixLuyKe_ToanBo
    @Nam INT
AS
BEGIN
    SET NOCOUNT ON;
    PRINT '=== BẮT ĐẦU CHẠY sp_FixLuyKe_ToanBo ===';

    ------------------------------------------------------------
    -- 2. DEDUPLICATE — gom theo mavt, tháng
    ------------------------------------------------------------
    IF OBJECT_ID('tempdb..#Dedup') IS NOT NULL DROP TABLE #Dedup;

    SELECT 
        mavt COLLATE SQL_Latin1_General_CP1_CI_AS AS mavt,
        ngay,
        MIN(sltondau) AS sltondau,
        SUM(ISNULL(slnhap,0)) AS slnhap,
        SUM(ISNULL(slxuat,0)) AS slxuat,
        MAX(ISNULL(sltoncuoi,0)) AS sltoncuoi,
        MAX(ISNULL(taikhoan,'')) AS taikhoan
    INTO #Dedup
    FROM tr_material_luyke
    WHERE YEAR(ngay) = @Nam AND loai = 'LuyKeThang'
    GROUP BY mavt, ngay;

    DELETE FROM tr_material_luyke WHERE YEAR(ngay) = @Nam AND loai = 'LuyKeThang';

    INSERT INTO tr_material_luyke (Id, loai, mavt, ngay, sltondau, slnhap, slxuat, sltoncuoi, dgton, taikhoan)
    SELECT NEWID(), 'LuyKeThang', mavt, ngay, sltondau, slnhap, slxuat, sltoncuoi, 0, taikhoan
    FROM #Dedup;

    PRINT '→ Đã gộp và làm sạch dữ liệu lũy kế.';

    ------------------------------------------------------------
    -- 3. FIX NỐI TIẾP VÀ BÙ ÂM
    ------------------------------------------------------------
    DECLARE @m INT = 1;
    WHILE @m <= 11
    BEGIN
        DECLARE @dCur DATE = DATEFROMPARTS(@Nam, @m, 1);
        DECLARE @dNext DATE = DATEADD(MONTH, 1, @dCur);

        PRINT CONCAT('--- Đang xử lý cặp: ', CONVERT(CHAR(7), @dCur, 120), ' -> ', CONVERT(CHAR(7), @dNext, 120));

        -- 1️⃣ Update tồn đầu tháng sau = tồn cuối tháng này
        UPDATE nxt
        SET nxt.sltondau = ISNULL(cur.sltoncuoi, 0)
        FROM tr_material_luyke nxt
        INNER JOIN tr_material_luyke cur
          ON cur.mavt COLLATE SQL_Latin1_General_CP1_CI_AS = nxt.mavt COLLATE SQL_Latin1_General_CP1_CI_AS
         AND cur.loai = 'LuyKeThang' AND nxt.loai = 'LuyKeThang'
         AND cur.ngay = @dCur AND nxt.ngay = @dNext
        WHERE YEAR(cur.ngay) = @Nam AND YEAR(nxt.ngay) = @Nam;

        -- 2️⃣ Tính lại tồn cuối
        UPDATE tr_material_luyke
        SET sltoncuoi = ISNULL(sltondau,0) + ISNULL(slnhap,0) - ISNULL(slxuat,0)
        WHERE loai = 'LuyKeThang' AND ngay = @dNext AND YEAR(ngay) = @Nam;

        -- 3️⃣ Nếu âm thì bù
        UPDATE tr_material_luyke
        SET sltondau = sltondau + ABS(sltoncuoi),
            sltoncuoi = 0
        WHERE loai = 'LuyKeThang' AND ngay = @dNext AND YEAR(ngay) = @Nam
          AND ISNULL(sltoncuoi,0) < 0;

        -- 4️⃣ Tính lại sau khi bù
        UPDATE tr_material_luyke
        SET sltoncuoi = ISNULL(sltondau,0) + ISNULL(slnhap,0) - ISNULL(slxuat,0)
        WHERE loai = 'LuyKeThang' AND ngay = @dNext AND YEAR(ngay) = @Nam;

        SET @m += 1;
    END;

    PRINT '→ Đã cập nhật nối tiếp và bù âm.';

    ------------------------------------------------------------
    -- 4. KIỂM TRA CHÊNH LỆCH SAU KHI FIX
    ------------------------------------------------------------
    IF OBJECT_ID('tempdb..#Diff') IS NOT NULL DROP TABLE #Diff;

    SELECT 
        a.mavt,
        a.ngay AS thangA,
        a.sltoncuoi AS toncuoiA,
        b.ngay AS thangB,
        b.sltondau AS tondauB,
        (b.sltondau - a.sltoncuoi) AS chenhlech
    INTO #Diff
    FROM tr_material_luyke a
    JOIN tr_material_luyke b
      ON a.mavt COLLATE SQL_Latin1_General_CP1_CI_AS = b.mavt COLLATE SQL_Latin1_General_CP1_CI_AS
     AND DATEADD(MONTH, 1, a.ngay) = b.ngay
    WHERE YEAR(a.ngay) = @Nam
      AND a.loai = 'LuyKeThang'
      AND b.loai = 'LuyKeThang'
      AND ABS(ISNULL(a.sltoncuoi,0) - ISNULL(b.sltondau,0)) > 0.0001;

    DECLARE @Count INT = (SELECT COUNT(*) FROM #Diff);
    PRINT CONCAT('→ Kiểm tra sau fix: còn ', @Count, ' dòng lệch.');

    IF @Count > 0
    BEGIN
        PRINT '⚠️ Có chênh lệch sau khi fix, kiểm tra bảng #Diff để biết chi tiết.';
        SELECT * FROM #Diff ORDER BY mavt, thangA;
    END
    ELSE
    BEGIN
        PRINT '✅ Toàn bộ số liệu đã khớp hoàn toàn.';
    END;

    PRINT '=== HOÀN TẤT sp_FixLuyKe_ToanBo ===';
END;
